import Foundation

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: String {
        switch self {
        case .development:
            return "https://api.example.com/dev"
        case .staging:
            return "https://api.example.com/staging"
        case .production:
            return "https://api.example.com"
        }
    }
}

class NetworkManager {
    static let shared = NetworkManager()
    
    private init() {}
    
    func fetchData(environment: Environment, completion: @escaping (Data?, Error?) -> Void) {
        guard let url = URL(string: environment.baseURL) else { return }
        
        let task = URLSession.shared.dataTask(with: url) { (data, response, error) in
            completion(data, error)
        }
        
        task.resume()
    }
    
    func authenticate(environment: Environment, username: String, password: String, completion: @escaping (Data?, Error?) -> Void) {
        guard let url = URL(string: "\(environment.baseURL)/authenticate") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        let body = "username=\(username)&password=\(password)"
        request.httpBody = body.data(using: .utf8)
        
        let task = URLSession.shared.dataTask(with: request) { (data, response, error) in
            completion(data, error)
        }
        
        task.resume()
    }
}